   170	        ObjectNode response = objectMapper.createObjectNode();
   171	        ArrayNode tagsArray = objectMapper.createArrayNode();
   172	        for (Map.Entry<String, String> entry : tags.entrySet()) {
   173	            ObjectNode tagNode = objectMapper.createObjectNode();
   174	            tagNode.put("Key", entry.getKey());
   175	            tagNode.put("Value", entry.getValue());
   176	            tagsArray.add(tagNode);
   177	        }
   178	        response.set("Tags", tagsArray);
