                if (attrNode.has("SS")) {
                    if (!searchAttrValue.has("S")) return false;
                    String target = searchAttrValue.get("S").asText();
                    for (JsonNode element : attrNode.get("SS")) {
                        if (target.equals(element.asText())) return true;
                    }
                    return false;
